import{_ as e,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"OpenCode: 插件安装 | Plannotator","description":"学习在 OpenCode 中安装 Plannotator 插件。通过配置 openable.json 添加插件，运行安装脚本获取斜杠命令，配置环境变量适配远程模式，验证插件是否正常工作。","frontmatter":{"title":"OpenCode: 插件安装 | Plannotator","sidebarTitle":"装上就能用","subtitle":"安装 OpenCode 插件","description":"学习在 OpenCode 中安装 Plannotator 插件。通过配置 openable.json 添加插件，运行安装脚本获取斜杠命令，配置环境变量适配远程模式，验证插件是否正常工作。","tags":["安装","配置","OpenCode"],"prerequisite":["start-getting-started"],"order":3},"headers":[],"relativePath":"zh/backnotprop/plannotator/start/installation-opencode/index.md","filePath":"zh/backnotprop/plannotator/start/installation-opencode/index.md"}'),i={name:"zh/backnotprop/plannotator/start/installation-opencode/index.md"};function s(l,t,d,r,p,h){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="安装-opencode-插件" tabindex="-1">安装 OpenCode 插件 <a class="header-anchor" href="#安装-opencode-插件" aria-label="Permalink to &quot;安装 OpenCode 插件&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>在 OpenCode 中安装 Plannotator 插件</li><li>配置 <code>submit_plan</code> tool 和 <code>/plannotator-review</code> 命令</li><li>设置环境变量（远程模式、端口、浏览器等）</li><li>验证插件安装是否成功</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>在 OpenCode 中使用 AI Agent 时，计划评审需要在终端阅读纯文本计划，难以精确反馈。你想要一个可视化界面来标注计划、添加注释，并自动将反馈结构化地发送回 Agent。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><p><strong>开始使用 Plannotator 前必做</strong>：如果你在 OpenCode 环境中开发，且希望获得交互式计划评审体验。</p><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>[ ] 已安装 <a href="https://opencode.ai/" target="_blank" rel="noreferrer">OpenCode</a></li><li>[ ] 了解基本的 <code>opencode.json</code> 配置（OpenCode 插件系统）</li></ul><div class="warning custom-block"><p class="custom-block-title">前置知识</p><p>如果你还不了解 OpenCode 的基本操作，建议先阅读 <a href="https://opencode.ai/docs" target="_blank" rel="noreferrer">OpenCode 官方文档</a>。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Plannotator 为 OpenCode 提供两个核心功能：</p><ol><li><strong><code>submit_plan</code> tool</strong> - 当 Agent 完成计划后调用，打开浏览器进行交互式评审</li><li><strong><code>/plannotator-review</code> 命令</strong> - 手动触发 Git diff 代码评审</li></ol><p>安装过程分两步：</p><ol><li>在 <code>opencode.json</code> 中添加插件配置（启用 <code>submit_plan</code> tool）</li><li>运行安装脚本（获取 <code>/plannotator-review</code> 命令）</li></ol><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-通过-opencode-json-安装插件" tabindex="-1">第 1 步：通过 opencode.json 安装插件 <a class="header-anchor" href="#第-1-步-通过-opencode-json-安装插件" aria-label="Permalink to &quot;第 1 步：通过 opencode.json 安装插件&quot;">​</a></h3><p>找到你的 OpenCode 配置文件（通常位于项目根目录或用户配置目录），在 <code>plugin</code> 数组中添加 Plannotator：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>为什么</strong><code>opencode.json</code> 是 OpenCode 的插件配置文件，添加插件名后，OpenCode 会自动从 npm 仓库下载并加载插件。</p><p>你应该看到：OpenCode 启动时会显示&quot;Loading plugin: @plannotator/opencode...&quot;的消息。</p><hr><h3 id="第-2-步-重启-opencode" tabindex="-1">第 2 步：重启 OpenCode <a class="header-anchor" href="#第-2-步-重启-opencode" aria-label="Permalink to &quot;第 2 步：重启 OpenCode&quot;">​</a></h3><p><strong>为什么</strong> 插件配置修改后需要重启才能生效。</p><p>你应该看到：OpenCode 重新加载所有插件。</p><hr><h3 id="第-3-步-运行安装脚本获取斜杠命令" tabindex="-1">第 3 步：运行安装脚本获取斜杠命令 <a class="header-anchor" href="#第-3-步-运行安装脚本获取斜杠命令" aria-label="Permalink to &quot;第 3 步：运行安装脚本获取斜杠命令&quot;">​</a></h3><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-pkEU6" id="tab-BHsyOAQ" checked><label data-title="macOS / Linux / WSL" for="tab-BHsyOAQ">macOS / Linux / WSL</label><input type="radio" name="group-pkEU6" id="tab-vh3KQCh"><label data-title="Windows PowerShell" for="tab-vh3KQCh">Windows PowerShell</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div></div></div><p><strong>为什么</strong> 这个脚本会：</p><ol><li>下载 <code>plannotator</code> CLI 工具到你的系统</li><li>将 <code>/plannotator-review</code> 斜杠命令安装到 OpenCode</li><li>清理任何缓存的插件版本</li></ol><p>你应该看到：安装成功提示，类似 &quot;Plannotator installed successfully!&quot;</p><hr><h3 id="第-4-步-验证安装" tabindex="-1">第 4 步：验证安装 <a class="header-anchor" href="#第-4-步-验证安装" aria-label="Permalink to &quot;第 4 步：验证安装&quot;">​</a></h3><p>在 OpenCode 中检查插件是否正常工作：</p><p><strong>检查 <code>submit_plan</code> tool 是否可用</strong>：</p><ul><li>在对话中询问 Agent &quot;请使用 submit_plan 提交计划&quot;</li><li>如果插件正常，Agent 应该能看到并调用这个 tool</li></ul><p><strong>检查 <code>/plannotator-review</code> 命令是否可用</strong>：</p><ul><li>在输入框中输入 <code>/plannotator-review</code></li><li>如果插件正常，应该能看到命令建议</li></ul><p>你应该看到：两个功能都能正常使用，没有错误提示。</p><hr><h3 id="第-5-步-配置环境变量-可选" tabindex="-1">第 5 步：配置环境变量（可选） <a class="header-anchor" href="#第-5-步-配置环境变量-可选" aria-label="Permalink to &quot;第 5 步：配置环境变量（可选）&quot;">​</a></h3><p>Plannotator 支持以下环境变量，根据你的需求配置：</p><details class="details custom-block"><summary>环境变量说明</summary><table tabindex="0"><thead><tr><th>环境变量</th><th>用途</th><th>默认值</th><th>示例</th></tr></thead><tbody><tr><td><code>PLANNOTATOR_REMOTE</code></td><td>启用远程模式（devcontainer/SSH）</td><td>未设置</td><td><code>export PLANNOTATOR_REMOTE=1</code></td></tr><tr><td><code>PLANNOTATOR_PORT</code></td><td>固定端口（远程模式必须）</td><td>本地随机，远程 19432</td><td><code>export PLANNOTATOR_PORT=9999</code></td></tr><tr><td><code>PLANNOTATOR_BROWSER</code></td><td>自定义浏览器路径</td><td>系统默认</td><td><code>export PLANNOTATOR_BROWSER=&quot;/Applications/Google Chrome.app&quot;</code></td></tr><tr><td><code>PLANNOTATOR_SHARE</code></td><td>禁用 URL 分享</td><td>启用</td><td><code>export PLANNOTATOR_SHARE=disabled</code></td></tr></tbody></table></details><p><strong>远程模式配置示例</strong>（devcontainer/SSH）：</p><p>在 <code>.devcontainer/devcontainer.json</code> 中：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;containerEnv&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PLANNOTATOR_REMOTE&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;PLANNOTATOR_PORT&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;9999&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;forwardPorts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">9999</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>为什么</strong></p><ul><li>远程模式：在容器或远程机器中运行 OpenCode 时，使用固定端口并自动打开浏览器</li><li>端口转发：让宿主机能访问容器内的服务</li></ul><p>你应该看到：当 Agent 调用 <code>submit_plan</code> 时，控制台会显示服务器 URL（而不是自动打开浏览器），例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plannotator server running at http://localhost:9999</span></span></code></pre></div><hr><h3 id="第-6-步-重启-opencode-如修改了环境变量" tabindex="-1">第 6 步：重启 OpenCode（如修改了环境变量） <a class="header-anchor" href="#第-6-步-重启-opencode-如修改了环境变量" aria-label="Permalink to &quot;第 6 步：重启 OpenCode（如修改了环境变量）&quot;">​</a></h3><p>如果你在第 5 步配置了环境变量，需要再次重启 OpenCode 让配置生效。</p><hr><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><p>安装完成后，确认以下几点：</p><ul><li>[ ] <code>opencode.json</code> 中已添加 <code>@plannotator/opencode@latest</code></li><li>[ ] OpenCode 重启后没有插件加载错误</li><li>[ ] 输入 <code>/plannotator-review</code> 能看到命令建议</li><li>[ ] （可选）环境变量配置正确</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="常见错误-1-插件加载失败" tabindex="-1">常见错误 1：插件加载失败 <a class="header-anchor" href="#常见错误-1-插件加载失败" aria-label="Permalink to &quot;常见错误 1：插件加载失败&quot;">​</a></h3><p><strong>症状</strong>：OpenCode 启动时提示 &quot;Failed to load plugin @plannotator/opencode&quot;</p><p><strong>可能原因</strong>：</p><ul><li>网络问题导致无法从 npm 下载</li><li>npm 缓存损坏</li></ul><p><strong>解决方法</strong>：</p><ol><li>检查网络连接</li><li>运行安装脚本（它会清理插件缓存）</li><li>手动清理 npm 缓存：<code>npm cache clean --force</code></li></ol><hr><h3 id="常见错误-2-斜杠命令不可用" tabindex="-1">常见错误 2：斜杠命令不可用 <a class="header-anchor" href="#常见错误-2-斜杠命令不可用" aria-label="Permalink to &quot;常见错误 2：斜杠命令不可用&quot;">​</a></h3><p><strong>症状</strong>：输入 <code>/plannotator-review</code> 没有命令建议</p><p><strong>可能原因</strong>：安装脚本未成功运行</p><p><strong>解决方法</strong>：重新运行安装脚本（步骤 3）</p><hr><h3 id="常见错误-3-远程模式下无法打开浏览器" tabindex="-1">常见错误 3：远程模式下无法打开浏览器 <a class="header-anchor" href="#常见错误-3-远程模式下无法打开浏览器" aria-label="Permalink to &quot;常见错误 3：远程模式下无法打开浏览器&quot;">​</a></h3><p><strong>症状</strong>：在 devcontainer 中调用 <code>submit_plan</code> 时浏览器未打开</p><p><strong>可能原因</strong>：</p><ul><li>未设置 <code>PLANNOTATOR_REMOTE=1</code></li><li>未配置端口转发</li></ul><p><strong>解决方法</strong>：</p><ol><li>确认 <code>PLANNOTATOR_REMOTE=1</code> 已设置</li><li>检查 <code>.devcontainer/devcontainer.json</code> 中 <code>forwardPorts</code> 包含你设置的端口</li><li>手动访问显示的 URL：<code>http://localhost:9999</code></li></ol><hr><h3 id="常见错误-4-端口占用" tabindex="-1">常见错误 4：端口占用 <a class="header-anchor" href="#常见错误-4-端口占用" aria-label="Permalink to &quot;常见错误 4：端口占用&quot;">​</a></h3><p><strong>症状</strong>：服务器启动失败，提示 &quot;Port already in use&quot;</p><p><strong>可能原因</strong>：之前的服务器未正确关闭</p><p><strong>解决方法</strong>：</p><ol><li>修改 <code>PLANNOTATOR_PORT</code> 为其他端口</li><li>或手动关闭占用端口的进程（macOS/Linux: <code>lsof -ti:9999 | xargs kill</code>）</li></ol><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>本课介绍了如何在 OpenCode 中安装和配置 Plannotator 插件：</p><ol><li><strong>通过 <code>opencode.json</code> 添加插件</strong> - 启用 <code>submit_plan</code> tool</li><li><strong>运行安装脚本</strong> - 获取 <code>/plannotator-review</code> 斜杠命令</li><li><strong>配置环境变量</strong> - 适配远程模式和自定义需求</li><li><strong>验证安装</strong> - 确认插件正常工作</li></ol><p>安装完成后，你可以：</p><ul><li>让 Agent 使用 <code>submit_plan</code> 提交计划进行交互式评审</li><li>使用 <code>/plannotator-review</code> 手动审查 Git diff</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../platforms/plan-review-basics/">计划评审基础</a></strong>。</p><p>你会学到：</p><ul><li>如何查看 AI 生成的计划</li><li>添加不同类型的注释（删除、替换、插入、评论）</li><li>批准或拒绝计划</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>插件入口定义</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>34-280</td></tr><tr><td><code>submit_plan</code> tool 定义</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>209-252</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>插件配置（opencode.json）注入</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>55-63</td></tr><tr><td>环境变量读取</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></td><td>37-51</td></tr><tr><td>计划评审服务器启动</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>全文</td></tr><tr><td>代码评审服务器启动</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>全文</td></tr><tr><td>远程模式检测</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/remote.ts" target="_blank" rel="noreferrer"><code>packages/server/remote.ts</code></a></td><td>全文</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE</code>: 远程模式标志（设置为 &quot;1&quot; 或 &quot;true&quot; 启用）</li><li><code>PLANNOTATOR_PORT</code>: 固定端口号（本地默认随机，远程默认 19432）</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>startPlannotatorServer()</code>: 启动计划评审服务器</li><li><code>startReviewServer()</code>: 启动代码评审服务器</li><li><code>getSharingEnabled()</code>: 获取 URL 分享开关状态（从 OpenCode 配置或环境变量）</li></ul></details>`,93)])])}const u=e(i,[["render",s]]);export{k as __pageData,u as default};
